<section class="admin-page-head"><div><p class="eyebrow">ATELIER</p><h1>Taxonomii editoriale</h1></div><a class="admin-button secondary" href="<?= e(url('/admin/atelier')) ?>">Articole</a></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><div class="admin-two-columns"><section class="admin-panel"><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Categorie</th><th>Slug</th><th>Articole</th><th>Indexabilă</th></tr></thead><tbody><?php foreach($categories as $category): ?><tr><td><strong><?= e($category['name']) ?></strong></td><td><?= e($category['slug']) ?></td><td><?= (int)$category['posts_count'] ?></td><td><?= $category['is_indexable']?'Da':'Nu' ?></td></tr><?php endforeach; ?></tbody></table></div></section><aside><form class="admin-panel" method="post" action="<?= e(url('/admin/atelier/taxonomii')) ?>"><?= csrf_field() ?><h2>Categorie nouă</h2><label>Nume<input name="name" required></label><label>Slug<input name="slug"></label><label>Descriere<textarea name="description"></textarea></label><label>Meta title<input name="meta_title"></label><label>Meta description<textarea name="meta_description"></textarea></label><label class="check-label"><input type="checkbox" name="is_active" value="1" checked> Activă</label><label class="check-label"><input type="checkbox" name="is_indexable" value="1" checked> Indexabilă</label><button class="admin-button" type="submit">Salvează</button></form></aside></div>
